import React, { useState, useEffect, useRef, useCallback } from 'react';
import '../styles/Challenges.css';

// ─── Helpers ──────────────────────────────────────────────────────────────────
const parseReward = (rewardStr) => {
  const xpMatch = rewardStr.match(/(\d+)\s*XP/);
  const xp = xpMatch ? parseInt(xpMatch[1]) : 0;
  const coins = Math.max(5, Math.round(xp * 0.2));
  return { xp, coins };
};

// ─── localStorage helpers (exported so Dashboard.js can import them) ──────────
export const getTodayStr     = () => new Date().toISOString().slice(0, 10);
export const getTodayKey     = () => `healup_daily_checked_${getTodayStr()}`;
export const CURRENT_DAY_KEY = 'healup_current_day';

export const loadChecked = () => {
  try { const s = localStorage.getItem(getTodayKey()); return s ? JSON.parse(s) : {}; }
  catch { return {}; }
};

export const saveChecked = (v) => {
  try { localStorage.setItem(getTodayKey(), JSON.stringify(v)); }
  catch {}
};

// ─── Day-rollover helper (exported so Dashboard.js can import it) ─────────────
export const checkDayRollover = () => {
  const today  = getTodayStr();
  const stored = localStorage.getItem(CURRENT_DAY_KEY);
  if (stored !== today) {
    localStorage.setItem(CURRENT_DAY_KEY, today);
    return { today, didRollover: true };
  }
  return { today, didRollover: false };
};

// ─── Full challenge pool (exported so Dashboard.js can import it) ─────────────
export const CHALLENGE_POOL = [
  // 🚶 Movement
  { title: 'Walk 8,000 steps',                        icon: '/footprint.png',      tags: [{ label: '30 XP', type: 'xp' }, { label: '+3 Energy', type: 'energy' }, { label: '+6 Coins', type: 'coins' }],   reward: '30 XP +3 Energy',               barEffects: { energy: 3 } },
  { title: 'Walk 10,000 steps',                       icon: '/footprint.png',      tags: [{ label: '50 XP', type: 'xp' }, { label: '+5 Energy', type: 'energy' }, { label: '+10 Coins', type: 'coins' }],  reward: '50 XP +5 Energy',               barEffects: { energy: 5 } },
  { title: 'Take a 15-minute walk',                   icon: '/footprint.png',      tags: [{ label: '20 XP', type: 'xp' }, { label: '+2 Energy', type: 'energy' }, { label: '+4 Coins', type: 'coins' }],   reward: '20 XP +2 Energy',               barEffects: { energy: 2 } },
  { title: 'Move for 5 min every hour',               icon: '/footprint.png',      tags: [{ label: '25 XP', type: 'xp' }, { label: '+3 Energy', type: 'energy' }, { label: '+5 Coins', type: 'coins' }],   reward: '25 XP +3 Energy',               barEffects: { energy: 3 } },
  { title: 'Use stairs instead of elevator',          icon: '/footprint.png',      tags: [{ label: '15 XP', type: 'xp' }, { label: '+2 Energy', type: 'energy' }, { label: '+3 Coins', type: 'coins' }],   reward: '15 XP +2 Energy',               barEffects: { energy: 2 } },
  { title: 'Do 20 jumping jacks',                     icon: '/footprint.png',      tags: [{ label: '20 XP', type: 'xp' }, { label: '+2 Energy', type: 'energy' }, { label: '+4 Coins', type: 'coins' }],   reward: '20 XP +2 Energy',               barEffects: { energy: 2 } },
  { title: 'Stand and move for 10 minutes',           icon: '/footprint.png',      tags: [{ label: '15 XP', type: 'xp' }, { label: '+2 Energy', type: 'energy' }, { label: '+3 Coins', type: 'coins' }],   reward: '15 XP +2 Energy',               barEffects: { energy: 2 } },
  { title: 'Walk after a meal for 10 minutes',        icon: '/footprint.png',      tags: [{ label: '20 XP', type: 'xp' }, { label: '+2 HP', type: 'hp' }, { label: '+4 Coins', type: 'coins' }],           reward: '20 XP +2 HP',                   barEffects: { hp: 2 } },
  { title: 'Take a sunlight walk',                    icon: '/footprint.png',      tags: [{ label: '25 XP', type: 'xp' }, { label: '+3 HP', type: 'hp' }, { label: '+5 Coins', type: 'coins' }],           reward: '25 XP +3 HP',                   barEffects: { hp: 3 } },
  { title: 'Walk while listening to a podcast',       icon: '/footprint.png',      tags: [{ label: '20 XP', type: 'xp' }, { label: '+2 Energy', type: 'energy' }, { label: '+4 Coins', type: 'coins' }],   reward: '20 XP +2 Energy',               barEffects: { energy: 2 } },
  // 💪 Workout
  { title: 'Complete a full workout',                 icon: '/workout.png',        tags: [{ label: '50 XP', type: 'xp' }, { label: '+5 Energy', type: 'energy' }, { label: '+2 Discipline', type: 'disc' }, { label: '+10 Coins', type: 'coins' }], reward: '50 XP +5 Energy +2 Discipline', barEffects: { energy: 5, discipline: 2 } },
  { title: 'Do 30 push-ups',                          icon: '/workout.png',        tags: [{ label: '30 XP', type: 'xp' }, { label: '+3 Energy', type: 'energy' }, { label: '+6 Coins', type: 'coins' }],   reward: '30 XP +3 Energy',               barEffects: { energy: 3 } },
  { title: 'Do 50 bodyweight squats',                 icon: '/workout.png',        tags: [{ label: '30 XP', type: 'xp' }, { label: '+3 Energy', type: 'energy' }, { label: '+6 Coins', type: 'coins' }],   reward: '30 XP +3 Energy',               barEffects: { energy: 3 } },
  { title: 'Hold a 1-minute plank',                   icon: '/workout.png',        tags: [{ label: '25 XP', type: 'xp' }, { label: '+2 Discipline', type: 'disc' }, { label: '+5 Coins', type: 'coins' }], reward: '25 XP +2 Discipline',           barEffects: { discipline: 2 } },
  { title: 'Do 10 burpees',                           icon: '/workout.png',        tags: [{ label: '35 XP', type: 'xp' }, { label: '+4 Energy', type: 'energy' }, { label: '+7 Coins', type: 'coins' }],   reward: '35 XP +4 Energy',               barEffects: { energy: 4 } },
  { title: 'Do a 15-minute workout',                  icon: '/workout.png',        tags: [{ label: '30 XP', type: 'xp' }, { label: '+3 Energy', type: 'energy' }, { label: '+6 Coins', type: 'coins' }],   reward: '30 XP +3 Energy',               barEffects: { energy: 3 } },
  { title: 'Complete 3 exercise sets',                icon: '/workout.png',        tags: [{ label: '25 XP', type: 'xp' }, { label: '+3 Energy', type: 'energy' }, { label: '+5 Coins', type: 'coins' }],   reward: '25 XP +3 Energy',               barEffects: { energy: 3 } },
  { title: 'Complete a home workout',                 icon: '/workout.png',        tags: [{ label: '40 XP', type: 'xp' }, { label: '+4 Energy', type: 'energy' }, { label: '+8 Coins', type: 'coins' }],   reward: '40 XP +4 Energy',               barEffects: { energy: 4 } },
  { title: 'Do core exercises',                       icon: '/workout.png',        tags: [{ label: '25 XP', type: 'xp' }, { label: '+2 Energy', type: 'energy' }, { label: '+2 Discipline', type: 'disc' }, { label: '+5 Coins', type: 'coins' }], reward: '25 XP +2 Energy +2 Discipline', barEffects: { energy: 2, discipline: 2 } },
  { title: 'Try a new exercise',                      icon: '/workout.png',        tags: [{ label: '30 XP', type: 'xp' }, { label: '+3 Energy', type: 'energy' }, { label: '+2 Discipline', type: 'disc' }, { label: '+6 Coins', type: 'coins' }], reward: '30 XP +3 Energy +2 Discipline', barEffects: { energy: 3, discipline: 2 } },
  // 🧘 Mobility / Stretching
  { title: 'Morning stretch (5 minutes)',             icon: '/exercising.png',     tags: [{ label: '15 XP', type: 'xp' }, { label: '+2 Energy', type: 'energy' }, { label: '+3 Coins', type: 'coins' }],   reward: '15 XP +2 Energy',               barEffects: { energy: 2 } },
  { title: 'Stretch before bed',                      icon: '/exercising.png',     tags: [{ label: '15 XP', type: 'xp' }, { label: '+2 HP', type: 'hp' }, { label: '+3 Coins', type: 'coins' }],           reward: '15 XP +2 HP',                   barEffects: { hp: 2 } },
  { title: '10-minute mobility routine',              icon: '/exercising.png',     tags: [{ label: '25 XP', type: 'xp' }, { label: '+3 Energy', type: 'energy' }, { label: '+5 Coins', type: 'coins' }],   reward: '25 XP +3 Energy',               barEffects: { energy: 3 } },
  { title: 'Stretch your hamstrings',                 icon: '/exercising.png',     tags: [{ label: '15 XP', type: 'xp' }, { label: '+2 HP', type: 'hp' }, { label: '+3 Coins', type: 'coins' }],           reward: '15 XP +2 HP',                   barEffects: { hp: 2 } },
  { title: 'Stretch your hips',                       icon: '/exercising.png',     tags: [{ label: '15 XP', type: 'xp' }, { label: '+2 HP', type: 'hp' }, { label: '+3 Coins', type: 'coins' }],           reward: '15 XP +2 HP',                   barEffects: { hp: 2 } },
  { title: 'Stretch your back',                       icon: '/exercising.png',     tags: [{ label: '15 XP', type: 'xp' }, { label: '+2 HP', type: 'hp' }, { label: '+3 Coins', type: 'coins' }],           reward: '15 XP +2 HP',                   barEffects: { hp: 2 } },
  { title: 'Neck mobility exercises',                 icon: '/exercising.png',     tags: [{ label: '15 XP', type: 'xp' }, { label: '+2 HP', type: 'hp' }, { label: '+3 Coins', type: 'coins' }],           reward: '15 XP +2 HP',                   barEffects: { hp: 2 } },
  { title: 'Shoulder mobility exercises',             icon: '/exercising.png',     tags: [{ label: '15 XP', type: 'xp' }, { label: '+2 HP', type: 'hp' }, { label: '+3 Coins', type: 'coins' }],           reward: '15 XP +2 HP',                   barEffects: { hp: 2 } },
  { title: 'Foam rolling session',                    icon: '/exercising.png',     tags: [{ label: '20 XP', type: 'xp' }, { label: '+3 HP', type: 'hp' }, { label: '+4 Coins', type: 'coins' }],           reward: '20 XP +3 HP',                   barEffects: { hp: 3 } },
  { title: 'Yoga flow (10 min)',                      icon: '/exercising.png',     tags: [{ label: '25 XP', type: 'xp' }, { label: '+3 HP', type: 'hp' }, { label: '+2 Energy', type: 'energy' }, { label: '+5 Coins', type: 'coins' }],  reward: '25 XP +3 HP +2 Energy',         barEffects: { hp: 3, energy: 2 } },
  // 💧 Health & Hydration
  { title: 'Drink 2L of water',                       icon: '/plastic-bottle.png', tags: [{ label: '20 XP', type: 'xp' }, { label: '+3 HP', type: 'hp' }, { label: '+4 Coins', type: 'coins' }],           reward: '20 XP +3 HP',                   barEffects: { hp: 3 } },
  { title: 'Drink water right after waking up',       icon: '/plastic-bottle.png', tags: [{ label: '15 XP', type: 'xp' }, { label: '+2 HP', type: 'hp' }, { label: '+3 Coins', type: 'coins' }],           reward: '15 XP +2 HP',                   barEffects: { hp: 2 } },
  { title: 'Drink water before each meal',            icon: '/plastic-bottle.png', tags: [{ label: '20 XP', type: 'xp' }, { label: '+3 HP', type: 'hp' }, { label: '+4 Coins', type: 'coins' }],           reward: '20 XP +3 HP',                   barEffects: { hp: 3 } },
  { title: 'Avoid sugary drinks today',               icon: '/plastic-bottle.png', tags: [{ label: '25 XP', type: 'xp' }, { label: '+3 Discipline', type: 'disc' }, { label: '+5 Coins', type: 'coins' }], reward: '25 XP +3 Discipline',           barEffects: { discipline: 3 } },
  { title: 'Drink herbal tea',                        icon: '/plastic-bottle.png', tags: [{ label: '15 XP', type: 'xp' }, { label: '+2 HP', type: 'hp' }, { label: '+3 Coins', type: 'coins' }],           reward: '15 XP +2 HP',                   barEffects: { hp: 2 } },
  { title: 'Track your water intake',                 icon: '/plastic-bottle.png', tags: [{ label: '15 XP', type: 'xp' }, { label: '+2 Discipline', type: 'disc' }, { label: '+3 Coins', type: 'coins' }], reward: '15 XP +2 Discipline',           barEffects: { discipline: 2 } },
  { title: 'Eat one piece of fruit',                  icon: '/healthy-food.png',   tags: [{ label: '15 XP', type: 'xp' }, { label: '+2 HP', type: 'hp' }, { label: '+3 Coins', type: 'coins' }],           reward: '15 XP +2 HP',                   barEffects: { hp: 2 } },
  { title: 'Eat a vegetable with a meal',             icon: '/healthy-food.png',   tags: [{ label: '20 XP', type: 'xp' }, { label: '+3 HP', type: 'hp' }, { label: '+4 Coins', type: 'coins' }],           reward: '20 XP +3 HP',                   barEffects: { hp: 3 } },
  { title: 'Avoid late night snacks',                 icon: '/no-sugar.png',       tags: [{ label: '25 XP', type: 'xp' }, { label: '+3 Discipline', type: 'disc' }, { label: '+5 Coins', type: 'coins' }], reward: '25 XP +3 Discipline',           barEffects: { discipline: 3 } },
  { title: 'Eat a high-protein meal',                 icon: '/healthy-food.png',   tags: [{ label: '25 XP', type: 'xp' }, { label: '+3 HP', type: 'hp' }, { label: '+5 Coins', type: 'coins' }],           reward: '25 XP +3 HP',                   barEffects: { hp: 3 } },
  // 🧠 Discipline / Habit
  { title: 'No sugary snacks today',                  icon: '/no-sugar.png',       tags: [{ label: '30 XP', type: 'xp' }, { label: '+3 Discipline', type: 'disc' }, { label: '+6 Coins', type: 'coins' }], reward: '30 XP +3 Discipline',           barEffects: { discipline: 3 } },
  { title: 'No soda today',                           icon: '/no-sugar.png',       tags: [{ label: '25 XP', type: 'xp' }, { label: '+3 Discipline', type: 'disc' }, { label: '+5 Coins', type: 'coins' }], reward: '25 XP +3 Discipline',           barEffects: { discipline: 3 } },
  { title: 'No junk food today',                      icon: '/no-sugar.png',       tags: [{ label: '35 XP', type: 'xp' }, { label: '+4 Discipline', type: 'disc' }, { label: '+7 Coins', type: 'coins' }], reward: '35 XP +4 Discipline',           barEffects: { discipline: 4 } },
  { title: 'Eat slowly and mindfully',                icon: '/healthy-food.png',   tags: [{ label: '20 XP', type: 'xp' }, { label: '+2 Discipline', type: 'disc' }, { label: '+4 Coins', type: 'coins' }], reward: '20 XP +2 Discipline',           barEffects: { discipline: 2 } },
  { title: 'Prepare a healthy meal',                  icon: '/healthy-food.png',   tags: [{ label: '30 XP', type: 'xp' }, { label: '+3 HP', type: 'hp' }, { label: '+2 Discipline', type: 'disc' }, { label: '+6 Coins', type: 'coins' }],  reward: '30 XP +3 HP +2 Discipline',     barEffects: { hp: 3, discipline: 2 } },
  { title: "Log today's food intake",                 icon: '/healthy-food.png',   tags: [{ label: '20 XP', type: 'xp' }, { label: '+2 Discipline', type: 'disc' }, { label: '+4 Coins', type: 'coins' }], reward: '20 XP +2 Discipline',           barEffects: { discipline: 2 } },
  { title: 'Track your steps today',                  icon: '/footprint.png',      tags: [{ label: '15 XP', type: 'xp' }, { label: '+2 Discipline', type: 'disc' }, { label: '+3 Coins', type: 'coins' }], reward: '15 XP +2 Discipline',           barEffects: { discipline: 2 } },
  { title: 'Sleep 7+ hours tonight',                  icon: '/sleeping-mask.png',  tags: [{ label: '35 XP', type: 'xp' }, { label: '+4 HP', type: 'hp' }, { label: '+7 Coins', type: 'coins' }],           reward: '35 XP +4 HP',                   barEffects: { hp: 4 } },
  { title: 'No phone during meals',                   icon: '/no-sugar.png',       tags: [{ label: '20 XP', type: 'xp' }, { label: '+2 Discipline', type: 'disc' }, { label: '+4 Coins', type: 'coins' }], reward: '20 XP +2 Discipline',           barEffects: { discipline: 2 } },
  { title: '10 minutes of mindfulness',               icon: '/exercising.png',     tags: [{ label: '25 XP', type: 'xp' }, { label: '+3 HP', type: 'hp' }, { label: '+2 Discipline', type: 'disc' }, { label: '+5 Coins', type: 'coins' }],  reward: '25 XP +3 HP +2 Discipline',     barEffects: { hp: 3, discipline: 2 } },
];

// ─── Daily challenge picker (exported so Dashboard.js can import it) ──────────
// Uses Park-Miller LCG seeded by date — Dashboard imports THIS exact function
// so both pages always pick the same 5 challenges for any given day.
export const getDailyChallenges = (dateStr) => {
  const today = dateStr || getTodayStr();
  let seed = parseInt(today.replace(/-/g, ''), 10); // e.g. 20260308

  const rand = () => {
    seed = (seed * 16807 + 0) % 2147483647;
    return (seed - 1) / 2147483646;
  };

  const shuffled = [...CHALLENGE_POOL];
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = Math.floor(rand() * (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }

  const movement   = shuffled.filter(c => c.icon === '/footprint.png');
  const workout    = shuffled.filter(c => c.icon === '/workout.png');
  const mobility   = shuffled.filter(c => c.icon === '/exercising.png');
  const hydration  = shuffled.filter(c => c.icon === '/plastic-bottle.png' || c.icon === '/healthy-food.png');
  const discipline = shuffled.filter(c => c.icon === '/no-sugar.png' || c.icon === '/sleeping-mask.png');

  return [movement[0], workout[0], mobility[0], hydration[0], discipline[0]].filter(Boolean);
};

// ─── Weekly challenges ────────────────────────────────────────────────────────
const weeklyChallenges = [
  { title: 'Run a total distance of 20 km in a week', progress: 40,  reward: '150 XP +50 Energy', icon: '/training.png' },
  { title: 'Share progress with a friend',            progress: 100, reward: '60 XP +20 Energy',  icon: '/collaborative-growth.png' },
  { title: 'Sleep 7-8 hours per night for 5 nights', progress: 70,  reward: '120 XP +40 Energy', icon: '/sleeping-mask.png' },
  { title: 'Drink 14L water total this week',         progress: 60,  reward: '100 XP +30 Energy', icon: '/plastic-bottle.png' },
];

// ─── Stat icon/color map ──────────────────────────────────────────────────────
const statMeta = {
  energy:     { icon: '/lighting.png',     label: 'Energy',     color: '#60a5fa' },
  hp:         { icon: '/health.png',       label: 'HP',         color: '#f87171' },
  discipline: { icon: '/roman-helmet.png', label: 'Discipline', color: '#a78bfa' },
};

// ─── Small components ─────────────────────────────────────────────────────────
const Img = ({ src, size = 28 }) => (
  <img src={src} alt="" style={{ width: size, height: size, objectFit: 'contain', flexShrink: 0 }} />
);

const FlyingParticle = ({ particle }) => (
  <div
    className="fly-particle"
    style={{
      '--start-x': `${particle.x}px`,
      '--start-y': `${particle.y}px`,
      '--tx': `${particle.tx}px`,
      '--ty': `${particle.ty}px`,
      '--delay': `${particle.delay}s`,
      '--color': particle.color,
      animationDelay: `${particle.delay}s`,
    }}
  >
    <img src={particle.icon} alt="" style={{ width: 24, height: 24, objectFit: 'contain', filter: `drop-shadow(0 0 4px ${particle.color})` }} />
  </div>
);

const RewardPopup = ({ popup }) => {
  if (!popup) return null;
  return (
    <div className="reward-popup-overlay">
      <div className="reward-popup">
        <div className="reward-popup-burst">
          <img src="/star.png" alt="" style={{ width: 48, height: 48, objectFit: 'contain', animation: 'burstSpin 0.6s ease' }} />
        </div>
        <div className="reward-popup-title">Challenge Complete!</div>
        <div className="reward-popup-rewards">
          <div className="reward-popup-item xp">
            <img src="/star.png" alt="XP" className="rp-icon-img" />
            <span className="rp-val">+{popup.xp} XP</span>
          </div>
          <div className="reward-popup-item coins">
            <img src="/profit.png" alt="Coins" className="rp-icon-img" />
            <span className="rp-val">+{popup.coins} Coins</span>
          </div>
          {popup.stat && (
            <div className="reward-popup-item stat">
              <img src={popup.stat.icon} alt={popup.stat.label} className="rp-icon-img" />
              <span className="rp-val">+{popup.stat.val} {popup.stat.label}</span>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

// ─── Main component ───────────────────────────────────────────────────────────
const Challenges = ({
  onChallengeComplete,
  bars = { hp: 65, energy: 80, discipline: 45 },
  streak = { count: 0 },
}) => {
  const [currentDay,      setCurrentDay]      = useState(() => getTodayStr());
  const [todayChallenges, setTodayChallenges] = useState(() => getDailyChallenges(getTodayStr()));
  const [isResetting,     setIsResetting]     = useState(false);
  const [justEntered,     setJustEntered]     = useState(true);
  const [checked,         setChecked]         = useState(() => loadChecked());
  const [justDone,        setJustDone]        = useState({});
  const [particles,       setParticles]       = useState([]);
  const [popup,           setPopup]           = useState(null);

  const itemRefs = useRef({});

  // ─── Day-rollover polling ────────────────────────────────────────────────
  useEffect(() => {
    const handleRollover = () => {
      const { today, didRollover } = checkDayRollover();

      if (didRollover) {
        setIsResetting(true);
        setJustEntered(false);
        setTimeout(() => {
          setTodayChallenges(getDailyChallenges(today));
          setCurrentDay(today);
          setChecked({});
          setIsResetting(false);
          setJustEntered(true);
          setTimeout(() => setJustEntered(false), 800);
        }, 600);
      } else {
        // Stay in sync if user checks challenges on Dashboard tab
        setChecked(loadChecked());
      }
    };

    handleRollover();
    const interval = setInterval(handleRollover, 2000);
    window.addEventListener('focus', handleRollover);
    document.addEventListener('visibilitychange', handleRollover);

    return () => {
      clearInterval(interval);
      window.removeEventListener('focus', handleRollover);
      document.removeEventListener('visibilitychange', handleRollover);
    };
  }, []);

  // ─── Derived values ──────────────────────────────────────────────────────
  const doneCount = Object.values(checked).filter(Boolean).length;
  const totalXP   = todayChallenges.reduce((sum, c) => {
    const m = c.reward.match(/(\d+)\s*XP/);
    return sum + (m ? parseInt(m[1]) : 0);
  }, 0);

  // ─── Particle spawner ────────────────────────────────────────────────────
  const spawnParticles = useCallback((originEl, xp, coins, barEffects) => {
    const rect    = originEl.getBoundingClientRect();
    const originX = rect.left + rect.width  / 2;
    const originY = rect.top  + rect.height / 2;

    const hpBar     = document.querySelector('.ch-stat-hp');
    const energyBar = document.querySelector('.ch-stat-energy');
    const discBar   = document.querySelector('.ch-stat-disc');
    const xpChip    = document.querySelector('.xp-chip');
    const coinChip  = document.querySelector('.coins-chip');

    const getCenter = (el) => {
      if (!el) return { x: window.innerWidth / 2, y: 60 };
      const r = el.getBoundingClientRect();
      return { x: r.left + r.width / 2, y: r.top + r.height / 2 };
    };

    const xpPos   = getCenter(xpChip);
    const coinPos = getCenter(coinChip);
    const now     = Date.now();
    const newParticles = [];

    for (let i = 0; i < 6; i++) {
      newParticles.push({ id: `${now}-xp-${i}`,   x: originX, y: originY, tx: xpPos.x   - originX + (Math.random() - 0.5) * 20, ty: xpPos.y   - originY, icon: '/star.png',   color: '#34d399', delay: i * 0.07 });
    }
    for (let i = 0; i < 6; i++) {
      newParticles.push({ id: `${now}-coin-${i}`, x: originX, y: originY, tx: coinPos.x - originX + (Math.random() - 0.5) * 20, ty: coinPos.y - originY, icon: '/profit.png', color: '#fbbf24', delay: 0.1 + i * 0.07 });
    }

    if (barEffects) {
      Object.entries(barEffects).forEach(([statKey], idx) => {
        const meta     = statMeta[statKey];
        if (!meta) return;
        const targetEl = statKey === 'hp' ? hpBar : statKey === 'energy' ? energyBar : discBar;
        const tPos     = getCenter(targetEl);
        for (let i = 0; i < 5; i++) {
          newParticles.push({ id: `${now}-stat-${statKey}-${i}`, x: originX, y: originY, tx: tPos.x - originX + (Math.random() - 0.5) * 30, ty: tPos.y - originY, icon: meta.icon, color: meta.color, delay: 0.15 + idx * 0.1 + i * 0.08 });
        }
      });
    }

    setParticles(prev => [...prev, ...newParticles]);
    setTimeout(() => setParticles(prev => prev.filter(p => !newParticles.find(n => n.id === p.id))), 3500);

    if (barEffects) {
      Object.entries(barEffects).forEach(([statKey]) => {
        setTimeout(() => {
          const sel = statKey === 'hp' ? '.ch-stat-hp' : statKey === 'energy' ? '.ch-stat-energy' : '.ch-stat-disc';
          const el  = document.querySelector(sel);
          if (el) { el.classList.add('bar-pulse'); setTimeout(() => el.classList.remove('bar-pulse'), 1000); }
        }, 1650);
      });
    }
  }, []);

  // ─── Check / Undo ────────────────────────────────────────────────────────
  const handleCheck = (index) => {
    if (checked[index]) return;
    const c = todayChallenges[index];

    const next = { ...checked, [index]: true };
    setChecked(next);
    saveChecked(next);

    setJustDone(prev => ({ ...prev, [index]: true }));
    setTimeout(() => setJustDone(prev => ({ ...prev, [index]: false })), 700);

    const { xp, coins } = parseReward(c.reward);
    if (onChallengeComplete) onChallengeComplete(xp, coins, c.barEffects);

    let statInfo = null;
    if (c.barEffects) {
      const [key, val] = Object.entries(c.barEffects)[0];
      const meta = statMeta[key];
      if (meta) statInfo = { icon: meta.icon, label: meta.label, val };
    }

    setPopup({ xp, coins, stat: statInfo });
    setTimeout(() => setPopup(null), 2800);

    const el = itemRefs.current[index];
    if (el) spawnParticles(el, xp, coins, c.barEffects);
  };

  const handleUndo = (index) => {
    const c    = todayChallenges[index];
    const next = { ...checked, [index]: false };
    setChecked(next);
    saveChecked(next);

    const { xp, coins } = parseReward(c.reward);
    if (onChallengeComplete) onChallengeComplete(
      -xp, -coins,
      c.barEffects ? Object.fromEntries(Object.entries(c.barEffects).map(([k, v]) => [k, -v])) : null
    );
  };

  // ─── Render ──────────────────────────────────────────────────────────────
  return (
    <>
      <div className="particles-root">
        {particles.map(p => <FlyingParticle key={p.id} particle={p} />)}
      </div>

      <RewardPopup popup={popup} />

      <div className="challenges-page">
        <div className="challenges-page-inner">

          {/* Header */}
          <div className="challenges-header">
            <div className="challenges-header-left">
              <div className="challenges-header-icon"><Img src="/challenges-icon-transparent.png" size={32} /></div>
              <div>
                <div className="challenges-header-title">Challenges</div>
                <div className="challenges-header-sub">Complete tasks to earn XP, coins and stat boosts</div>
              </div>
            </div>
            <div className="challenges-header-stats">
              <div className="ch-header-stat">
                <span className="ch-header-stat-val gold">{doneCount}/{todayChallenges.length}</span>
                <span className="ch-header-stat-label">Daily Done</span>
              </div>
              <div className="ch-header-stat">
                <span className="ch-header-stat-val blue">{totalXP}</span>
                <span className="ch-header-stat-label">Max XP Today</span>
              </div>
              <div className="ch-header-stat">
                <span className="ch-header-stat-val green">
                  {weeklyChallenges.filter(c => c.progress === 100).length}/{weeklyChallenges.length}
                </span>
                <span className="ch-header-stat-label">Weekly Done</span>
              </div>
              <div className={`ch-header-stat streak-stat ${streak.count >= 3 ? 'streak-hot' : ''}`}>
                <span className="ch-header-stat-val streak-val">🔥 {streak.count}</span>
                <span className="ch-header-stat-label">Day Streak</span>
                {streak.count >= 3 && (
                  <span className="streak-bonus-badge">+{Math.min(streak.count * 10, 100)}% XP</span>
                )}
              </div>
            </div>
          </div>

          {/* Stat Bars */}
          <div className="ch-stat-bars-panel">
            {[
              { src: '/health.png',       label: 'HP',         cls: 'ch-stat-hp',     val: bars.hp },
              { src: '/lighting.png',     label: 'Energy',     cls: 'ch-stat-energy', val: bars.energy },
              { src: '/roman-helmet.png', label: 'Discipline', cls: 'ch-stat-disc',   val: bars.discipline },
            ].map(({ src, label, cls, val }) => (
              <div className="ch-stat-bar-row" key={label}>
                <Img src={src} size={24} />
                <div className="ch-stat-label-text">{label}</div>
                <div className="ch-stat-track">
                  <div className={`ch-stat-fill ${cls}`} style={{ width: `${val}%`, transition: 'width 0.6s ease' }} />
                  <span className="ch-stat-pct">{val}%</span>
                </div>
              </div>
            ))}
          </div>

          {/* Grid */}
          <div className="challenges-grid">

            {/* Daily */}
            <div className="challenges-section">
              <div className="challenges-section-header">
                <div className="ch-section-title">
                  <div className="ch-section-dot" />
                  Daily Challenges
                </div>
                <div className="ch-section-progress-badge">{doneCount}/{todayChallenges.length} Complete</div>
              </div>
              <div className="challenges-list">
                {todayChallenges.map((c, i) => (
                  <div
                    key={`${currentDay}-${i}`}
                    ref={el => itemRefs.current[i] = el}
                    className={[
                      'ch-item',
                      checked[i]  ? 'ch-completed'      : '',
                      justDone[i] ? 'ch-just-completed' : '',
                      isResetting ? 'ch-resetting'      : '',
                      justEntered ? 'ch-entering'        : '',
                    ].join(' ').trim()}
                    style={(isResetting || justEntered) ? { animationDelay: `${i * 80}ms` } : {}}
                    onClick={() => handleCheck(i)}
                    data-testid={`daily-challenge-${i}`}
                  >
                    <div className={`ch-custom-check ${checked[i] ? 'checked' : ''}`}>
                      {checked[i] && <span className="ch-check-icon">✓</span>}
                    </div>
                    <Img src={c.icon} size={30} />
                    <div className="ch-item-body">
                      <div className="ch-item-title">{c.title}</div>
                      <div className="ch-item-tags">
                        {c.tags.map((tag, ti) => (
                          <span key={ti} className={`ch-tag ${tag.type}`}>{tag.label}</span>
                        ))}
                      </div>
                    </div>
                    <div className="ch-reward-badge">
                      {checked[i] ? (
                        <button className="ch-undo-btn" onClick={e => { e.stopPropagation(); handleUndo(i); }}>
                          <span style={{ fontSize: '0.9rem' }}>↩</span> Undo
                        </button>
                      ) : (
                        <>
                          <img src="/star.png" alt="XP" className="ch-preview-icon" title="XP" />
                          {c.barEffects && Object.keys(c.barEffects).map(statKey => {
                            const meta = statMeta[statKey];
                            return meta ? <img key={statKey} src={meta.icon} alt={meta.label} className="ch-preview-icon" title={meta.label} /> : null;
                          })}
                          <div className="ch-reward-icon">
                            <img src="/profit.png" alt="Coins" style={{ width: 18, height: 18, objectFit: 'contain' }} />
                          </div>
                        </>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Weekly */}
            <div className="challenges-section">
              <div className="challenges-section-header">
                <div className="ch-section-title">
                  <div className="ch-section-dot" style={{ background: '#fbbf24', boxShadow: '0 0 8px #fbbf24' }} />
                  Weekly Challenges
                </div>
                <div className="ch-section-progress-badge">Resets in 4 days</div>
              </div>
              <div className="challenges-list">
                {weeklyChallenges.map((c, i) => (
                  <div key={i} className="ch-weekly-item" data-testid={`weekly-challenge-${i}`}>
                    <div className="ch-weekly-top">
                      <Img src={c.icon} size={28} style={{ marginRight: '0.4rem' }} />
                      <div className="ch-weekly-title">{c.title}</div>
                      <div className="ch-weekly-pct">{c.progress}%</div>
                    </div>
                    <div className="ch-weekly-track">
                      <div className={`ch-weekly-fill ${c.progress === 100 ? 'complete' : ''}`} style={{ width: `${c.progress}%` }} />
                    </div>
                    <div className="ch-weekly-bottom">
                      <div className="ch-weekly-reward">
                        <img src="/lighting.png" alt="" style={{ width: 16, height: 16, objectFit: 'contain' }} />
                        <span className="ch-weekly-reward-text">{c.reward}</span>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

          </div>
        </div>
      </div>
    </>
  );
};

export default Challenges;
